+        conn1.execute("BEGIN;").unwrap();
+        conn2.execute("BEGIN;").unwrap();
+
+        // Both read the current value.
+        let _rows1 = conn1.query("SELECT val FROM conflict_tbl WHERE id = 1;").unwrap();
