+#[test]
+fn bead_metadata_constants_are_stable_for_replay() {
+    assert_eq!(BEAD_ID, "bd-2yqp6.6.5");
+    assert_eq!(SCENARIO_ID, "CONCURRENT-DEFAULTS-F5");
+    assert_eq!(SEED, 3520);
+}

