+            #[test]
+            fn prop_eviction_metrics_consistent(
+                capacity in 2..6usize,
+                ops in proptest::collection::vec(1..50u32, 1..40)
+            ) {
+                let max_bytes = capacity * 4096;
+                let mut cache = ArcCache::new(capacity, max_bytes);
+                let mut total_inserts = 0usize;
