+        scenario_id,
+        seed,
+        "truncated_tail_stop",
+        3,
+        frames.len(),
+        Some(2),
+        digest,
+    );
+}
+
+#[test]
+fn scenario_duplicate_frames_remain_deterministic() {
+    let scenario_id = "WAL-REPLAY-STARTUP-DUPLICATE-FRAMES";
+    let seed = 2663102_u64;
+    let cx = test_cx();
+    let vfs = MemoryVfs::new();
+    write_frames(&vfs, &cx, seed, &DUPLICATE_FRAMES);
+
