+        digest,
+    );
+}
+
+#[test]
+fn scenario_commit_boundary_drops_uncommitted_tail() {
+    let scenario_id = "WAL-REPLAY-STARTUP-COMMIT-BOUNDARY";
+    let seed = 2663103_u64;
